import{_ as e,c as t,o as a,a5 as s}from"./chunks/framework.dGPInWOZ.js";const h=JSON.parse('{"title":"域名由来","description":"","frontmatter":{"layout":"doc","prev":false,"next":false,"sidebar":false,"aside":false},"headers":[],"relativePath":"name.md","filePath":"name.md"}'),p={name:"name.md"},o=s('<h1 id="域名由来" tabindex="-1">域名由来 <a class="header-anchor" href="#域名由来" aria-label="Permalink to &quot;域名由来&quot;">​</a></h1><p>fcbyk 是 非常不愉快 的每个字的首拼音组合<br> 非常不愉快这个名字源于昵称重复</p><blockquote><p>很久很久以前，我在某APP设置昵称 <br> 具体的 APP/游戏 和 当时想设置的昵称忘了，以网易云音乐APP和小明昵称举例</p></blockquote><p>我尝试了 小明，小小明，明小，名字重复，id重复，为什么，我趣，????.....</p><hr><p><img src="https://user-images.githubusercontent.com/101487905/211132451-e4f08849-4ee0-411f-8882-7c84a3862146.gif" alt=""></p><hr><p>由于很多昵称被占用，之后又是各种无脑尝试，比如大雄的同桌，胖虎的同桌，不开心，不高兴，没头脑，不愉快，非常不开心.....</p><p><img src="https://user-images.githubusercontent.com/101487905/211133219-7f840601-6a2f-4aab-a3d0-e8ab7b189f99.png" alt=""></p><p>最后只有非常不愉快这个昵称没有重复。然后就没有多想，后面也懒得改，一直都是用这个昵称</p><p>之后遇到的其他不能重名的APP或游戏，都是优先使用非常不愉快这个昵称。比如王者荣耀，不能重名（下面是网图，不是截图）</p><p><img src="https://user-images.githubusercontent.com/101487905/211133769-74cc86ce-190b-48d7-80ee-4b7b80825734.png" alt=""></p><p>有的时候非常不愉快也会重名，之后慢慢衍生出不愉快，不愉，不是不余这些昵称</p><p>不知不觉，非常不愉快这个昵称陪伴了我好久，之后也不太想改</p><p>不愉快，在这里，没有emo和负能量的意思</p>',15),r=[o];function c(n,i,_,m,l,d){return a(),t("div",null,r)}const u=e(p,[["render",c]]);export{h as __pageData,u as default};
